updateFields.birthdate:
={{
  DateTime
    .fromMillis(
      Number($('Contact tagged in KlickTipp').item.json.fieldBirthday) * 1000,
      { zone: 'Europe/Berlin' }
    )
    .toFormat('yyyy-MM-dd')
}}

